function renderAll(appsList) {
    // 1. Render Home Pager Pages
    const pager = document.getElementById('home-pager');
    if (!pager) return;

    pager.innerHTML = homePages.map((pageShortcuts, pageIdx) => `
        <div class="home-page-view">
            <div class="home-content" onclick="launchClock()">
                <div class="main-clock">00:00</div>
                <div class="main-date">...</div>
            </div>
            <div class="home-grid">
                ${pageShortcuts.map(pkg => {
                    const app = allApps.find(a => a.pkg === pkg);
                    if (!app) return '';
                    return `
                        <div class="app-item" 
                             oncontextmenu="return false;"
                             onclick="CortexLauncher.launch('${app.pkg}')" 
                             ontouchstart="handlePressStart(event, '${app.pkg}', false, true, ${pageIdx})" 
                             ontouchend="handlePressEnd(event)" 
                             ontouchmove="handlePressEnd(event)">
                            <img class="app-icon" src="${app.icon}">
                            <div class="app-label">${app.name}</div>
                        </div>
                    `;
                }).join('')}
            </div>
        </div>
    `).join('');

    updateTime();

    // 2. Render Dock
    const activeDockApps = [];
    dockPkgs.forEach(pkg => {
        const match = allApps.find(a => a.pkg.toLowerCase().includes(pkg.toLowerCase()));
        if (match && !activeDockApps.find(d => d.pkg === match.pkg)) activeDockApps.push(match);
    });

    dock.innerHTML = activeDockApps.slice(0, 4).map(app => `
        <div class="app-item" 
             oncontextmenu="return false;"
             onclick="CortexLauncher.launch('${app.pkg}')" 
             ontouchstart="handlePressStart(event, '${app.pkg}', true, false)" 
             ontouchend="handlePressEnd(event)" 
             ontouchmove="handlePressEnd(event)">
            <img class="app-icon" src="${app.icon}">
        </div>
    `).join('');

    // Render Grid
    const pager = document.getElementById('pager');
    const dots = document.getElementById('dots');
    pager.innerHTML = ''; dots.innerHTML = '';

    for (let i = 0; i < appsList.length; i += 24) {
        const chunk = appsList.slice(i, i + 24);
        const page = document.createElement('div');
        page.className = 'grid-page';
        page.innerHTML = chunk.map(app => `
            <div class="app-item" 
                 oncontextmenu="return false;"
                 onclick="CortexLauncher.launch('${app.pkg}')" 
                 ontouchstart="handlePressStart(event, '${app.pkg}', false, false)" 
                 ontouchend="handlePressEnd(event)" 
                 ontouchmove="handlePressEnd(event)">
                <img class="app-icon" src="${app.icon}" loading="lazy">
                <div class="app-label">${app.name}</div>
            </div>
        `).join('');
        pager.appendChild(page);
        const dot = document.createElement('div');
        dot.className = 'dot' + (i === 0 ? ' active' : '');

        // Teleportation Logic
        const pageIdx = Math.floor(i / 24);
        dot.onclick = () => jumpToPage(pageIdx);

        dots.appendChild(dot);
    }
}

